import React, { useState } from 'react';
import axios from 'axios';
import Dropzone from 'react-dropzone';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [targetColumn, setTargetColumn] = useState('diagnosis');
  const [dropColumns, setDropColumns] = useState('id');
  const [results, setResults] = useState('');
  const [loading, setLoading] = useState(false);

  const onDrop = (acceptedFiles) => {
    setFile(acceptedFiles[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      alert('Please select a CSV file');
      return;
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('file', file);
    formData.append('targetColumn', targetColumn);
    formData.append('dropColumns', dropColumns);

    try {
      const response = await axios.post('http://localhost:5000/predict', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      setResults(response.data.results);
    } catch (error) {
      setResults(`Error: ${error.message}`);
    }
    setLoading(false);
  };

  return (
    <div className="App">
      <h1>Machine Learning Classifier</h1>

      <form onSubmit={handleSubmit}>
        <div className="input-group">
          <label>File Upload:</label>
          <Dropzone
            onDrop={onDrop}
            accept={{ 'text/csv': ['.csv'] }}
            multiple={false}
          >
            {({ getRootProps, getInputProps }) => (
              <section className="dropzone">
                <div {...getRootProps()}>
                  <input {...getInputProps()} />
                  {file ? (
                    <p>Selected file: {file.name}</p>
                  ) : (
                    <p>Drag 'n' drop a CSV file here, or click to select</p>
                  )}
                </div>
              </section>
            )}
          </Dropzone>
        </div>

        <div className="input-group">
          <label>Target Column:</label>
          <input
            type="text"
            value={targetColumn}
            onChange={(e) => setTargetColumn(e.target.value)}
          />
        </div>

        <div className="input-group">
          <label>Columns to Drop (comma-separated):</label>
          <input
            type="text"
            value={dropColumns}
            onChange={(e) => setDropColumns(e.target.value)}
          />
        </div>

        <button type="submit" disabled={loading}>
          {loading ? 'Processing...' : 'Run Model'}
        </button>
      </form>

      <div className="results">
        <h2>Results:</h2>
        <pre>{results}</pre>
      </div>
    </div>
  );
}

export default App;
